return items.map((item) => {
  const root = item.json || {};
  const body = root.body || {};
  const data = root.data || {};

  const fileBase64 =
    root.file_content_base64 ||
    body.file_content_base64 ||
    data.file_content_base64 ||
    root.file_data ||
    body.file_data ||
    data.file_data;

  const specId =
    root.spec_id ||
    body.spec_id ||
    data.spec_id ||
    root.specId ||
    body.specId ||
    data.specId;

  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };

  const fileName =
    root.file_name ||
    body.file_name ||
    data.file_name ||
    'Spec.pdf';

  if (!fileBase64) {
    throw new Error(`Webhook payload missing file_content_base64. Keys: ${Object.keys(root).join(', ')}`);
  }

  // Simple deterministic hash (no crypto required)
  const hashDjb2 = (str) => {
    let h = 5381;
    for (let i = 0; i < str.length; i++) {
      h = ((h << 5) + h) + str.charCodeAt(i);
      h |= 0;
    }
    return (h >>> 0).toString(16);
  };

  const pdfFingerprint = hashDjb2(fileBase64);

  return {
    json: {
      ...root,
      ...(Object.keys(body).length ? body : {}),
      ...(Object.keys(data).length ? data : {}),
      file_name: fileName,
      file_content_base64: fileBase64,
      pdf_fingerprint: pdfFingerprint,
      spec_id: normalizeId(specId),
    },
    binary: {
      data0: {
        data: fileBase64,
        mimeType: 'application/pdf',
        fileName,
      },
    },
  };
});

const promises = items.map(async (item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};
  let pdf = j.file_content_base64 || original.file_content_base64 || j.file_data || original.file_data || '';

  if (!pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, 'data0');
      pdf = buf.toString('base64');
    } catch (e) {}
  }

  const prompt = `You are an expert extractor for customer steel specification PDFs.
Return ONLY valid JSON. No commentary.

Strict JSON schema:
{
  "spec_name": "",
  "revision": "",
  "customer": "",
  "astm_equivalent": [],
  "requires_impact": false,
  "requires_ce": false,
  "ce_formula": "",
  "chem_limits": [
    {"element": "c", "min": 0.0, "max": 0.0, "source": "table"}
  ],
  "mech_limits": [
    {"property": "yield", "min": 0.0, "max": 0.0, "unit": "ksi", "specimen_size": ""}
  ],
  "impact_limits": [
    {"temperature": 0.0, "coupon_size": "", "min_average": 0.0, "min_individual": 0.0, "unit": "j", "min_readings": 3, "orientation": ""}
  ],
  "condition_rules": [
    {"target_element": "mn", "condition_element": "c", "condition_type": "decrease_by", "condition_threshold": 0.01, "target_adjustment": 0.05, "target_new_max": 1.6, "description": ""}
  ],
  "ce_thresholds": [
    {"thickness_min": 0.0, "thickness_max": 0.0, "max_ce": 0.0}
  ]
}

Rules:
- astm_equivalent must be an array of strings and MUST include every ASTM/ASME/API equivalent mentioned anywhere (tables, notes, footnotes). If none, return an empty array.
- Use lowercase element keys: c, mn, si, p, s, cu, ni, cr, mo, n, v.
- If a min or max is not specified, use null (never 0 unless the spec explicitly says 0).
- If a section is not specified in the spec, return an empty array for that section.
- requires_impact and requires_ce must be true/false.
- Use numbers for numeric values, not strings.
- Use a dot only for decimals and NEVER use thousands separators. If the document uses commas or spaces as thousands separators, remove them before output (e.g., "12,500" -> 12500; "1 250" -> 1250).
- If the document uses comma as decimal (e.g., 0,25), convert to dot (0.25).
- If mechanical values are written in PSI (e.g., 50,000 psi), convert to KSI by dividing by 1000 and set unit to ksi (e.g., 50,000 psi -> 50 ksi).
- Keep the numeric magnitude consistent with the document: chemistry limits are usually small decimals (<5), while mechanical values (yield/tensile/elongation/hardness) are much larger (often tens of thousands in psi or hundreds in MPa).
- Use a dot only for decimals and NEVER use thousands separators. If the document uses commas or spaces as thousands separators, remove them before output (e.g., "12,500" -> 12500; "1 250" -> 1250).
- If the document uses comma as decimal (e.g., 0,25), convert to dot (0.25).
- Keep the numeric magnitude consistent with the document: chemistry limits are usually small decimals (<5), while mechanical values (yield/tensile/elongation/hardness) are much larger (often tens of thousands in psi or hundreds in MPa).
- Units must be normalized to one of: ksi, mpa, %, bhn, j, ftlb.
- For impact units use only j or ftlb (no ft-lbs, ft lb, etc.).
- Do not invent limits not present.`;
  if (!pdf || !prompt) {
    throw new Error('Missing pdf or prompt');
  }

  return {
    json: {
      ...original,
      ...j,
      file_content_base64: original.file_content_base64 || j.file_content_base64,
      claude_extract_body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 4096,
        messages: [
          {
            role: 'user',
            content: [
              { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdf } },
              { type: 'text', text: prompt }
            ]
          }
        ]
      }
    }
  };
});

return Promise.all(promises);

return items.map((item, idx) => {
  const j = item.json || {};
  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};
  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }
  return {
    json: {
      ...j,
      output: obj,
    },
    binary: item.binary
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;
  return {
    json: {
      spec_id: j.spec_id || original.spec_id || original.specId || '',
      output: out,
    }
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};
  const normalizeImpactUnit = (u) => {
    const s = String(u || '').trim().toLowerCase();
    if (['ft-lb','ft-lbs','ftlb','ftlbs','ft lb','ft lbs'].includes(s)) return 'ftlb';
    if (['j','joule','joules'].includes(s)) return 'j';
    return s || 'j';
  };
  const normalizeEquivalents = (v) => {
    if (!v) return '';
    if (Array.isArray(v)) return v.filter(Boolean).join(', ');
    if (typeof v === 'string') return v;
    return String(v);
  };
  const normalizeNumber = (v) => {
    if (v === null || v === undefined || v === '') return v;
    if (typeof v === 'number') return v;
    const s = String(v).trim();
    if (!s) return v;
    const cleaned = s.replace(/,/g, '');
    const n = Number(cleaned);
    return Number.isFinite(n) ? n : v;
  };
  const normalizeMechValue = (v, unit) => {
    const n = normalizeNumber(v);
    if (n === null || n === undefined || n === '') return n;
    if (unit === 'ksi' && typeof n === 'number' && n > 1000) {
      return n / 1000;
    }
    return n;
  };
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;
  return {
    json: {
      token: j.spec_ingest_token || '',
      spec_id: j.spec_id || (original && (original.spec_id || original.specId)) || '',
      spec_name: out.spec_name || j.spec_name || '',
      revision: out.revision || '',
      customer: out.customer || '',
      astm_equivalent: normalizeEquivalents(out.astm_equivalent || out.astm_equivalents),
      requires_impact: !!out.requires_impact,
      requires_ce: !!out.requires_ce,
      ce_formula: out.ce_formula || '',
      chem_limits: Array.isArray(out.chem_limits) ? out.chem_limits.map(l => ({...l, min: normalizeNumber(l.min), max: normalizeNumber(l.max)})) : [],
      mech_limits: Array.isArray(out.mech_limits) ? out.mech_limits.map(l => ({...l, min: normalizeMechValue(l.min, (l.unit || '').toLowerCase()), max: normalizeMechValue(l.max, (l.unit || '').toLowerCase())})) : [],
      impact_limits: Array.isArray(out.impact_limits) ? out.impact_limits.map(l => ({...l, unit: normalizeImpactUnit(l.unit), temperature: normalizeNumber(l.temperature), min_average: normalizeNumber(l.min_average), min_individual: normalizeNumber(l.min_individual)})) : [],
      condition_rules: Array.isArray(out.condition_rules) ? out.condition_rules.map(l => ({...l, condition_threshold: normalizeNumber(l.condition_threshold), target_adjustment: normalizeNumber(l.target_adjustment), target_new_max: normalizeNumber(l.target_new_max)})) : [],
      ce_thresholds: Array.isArray(out.ce_thresholds) ? out.ce_thresholds.map(l => ({...l, thickness_min: normalizeNumber(l.thickness_min), thickness_max: normalizeNumber(l.thickness_max), max_ce: normalizeNumber(l.max_ce)})) : [],
      db_name: j.db_name || (original && (original.db_name || original.database)) || '',
      odoo_url: j.odoo_url || 'https://brannon.eoxs.com'
    }
  };
});
